// === УТРЕННИЙ БРИФИНГ ===
// Форматируем отчёт по Fear & Greed и текущей цене BTC

const items = $input.all();

// Fear & Greed Index
let fngValue = 50;
let fngClassification = 'Neutral';
try {
  const fngData = items[0]?.json?.data?.[0] || items[0]?.json;
  fngValue = parseInt(fngData?.value || 50);
  fngClassification = fngData?.value_classification || 'Neutral';
} catch(e) {
  fngValue = 50;
  fngClassification = 'N/A';
}

// BTC Price
let btcPrice = 0;
try {
  const tickerData = items[1]?.json?.data?.[0] || items[1]?.json?.data || items[1]?.json;
  btcPrice = parseFloat(tickerData?.lastPr || tickerData?.close || 0);
} catch(e) {
  btcPrice = 0;
}

// Рекомендация на основе Fear & Greed
let recommendation = '';
let emoji = '';
if (fngValue >= 75) {
  recommendation = '⚠️ ОСТОРОЖНО — Extreme Greed. Рынок перегрет, избегайте крупных позиций';
  emoji = 'ð´';
} else if (fngValue >= 55) {
  recommendation = '✅ ТОРГОВАТЬ — Умеренный оптимизм. Торги согласно сигналам';
  emoji = 'ð¢';
} else if (fngValue >= 25) {
  recommendation = '⚡ ТОРГОВАТЬ ОСТОРОЖНО — Нейтральный рынок. Уменьшенные позиции';
  emoji = 'ð¡';
} else {
  recommendation = 'ð СТОП — Extreme Fear. Только консервативные ордера';
  emoji = 'ð´';
}

const now = new Date();
const dateStr = now.toLocaleDateString('ru-RU', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

return [{
  json: {
    btcPrice: btcPrice.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 }),
    fngValue,
    fngClassification,
    recommendation,
    emoji,
    dateStr,
    message: `☀️ <b>Доброе утро! Дневной брифинг</b>\nð ${dateStr}\n\nð° BTC: <code>$${btcPrice.toLocaleString('en-US', { minimumFractionDigits: 2 })}</code>\n\nð± Fear \u0026 Greed: <b>${fngValue}</b> (${fngClassification}) ${emoji}\n${'█'.repeat(Math.floor(fngValue / 5))}${'░'.repeat(20 - Math.floor(fngValue / 5))} ${fngValue}%\n\n${recommendation}\n\nð Пары: BTC ETH SOL BNB\n⏰ Следующий анализ через 15 мин`
  }
}];
